import pandas as pd

brics = pd.read_csv('brics.csv', index_col=0)
large_brics = brics[brics['area'] > 5]

def density(row):
    return round(row['population'] / row['area'], 2)

large_brics['density'] = large_brics.apply(density, axis=1)

for idx, row in large_brics.iterrows():
    print(f"Country: {row['country']}, Area: {row['area']} million km², Population density: {row['density']} people per km²")
